// packages/renderer/src/plugins/views.ts
//
// The View system (built-in plugin).
//
//   • A ViewTemplate (workspace-global) is header/row/footer HTML that decides
//     how a table is displayed. Blank row HTML ⇒ a read-only columns table;
//     otherwise the row HTML repeats per row with $TOKEN placeholders.
//   • A ViewInstance ties a template to ONE table, snapshotting its sort /
//     filter / visible columns and mapping the template's $TOKENs to columns.
//     It opens read-only in its own window.
//
// This plugin owns only DATA + INTENT: it seeds the default "RSS Feed" template
// and adds a "Views" button to each table's footer (opening the manager
// dialog). The actual view *windows* — opening, geometry, persistence, maximize
// behaviour, and boot-time restore — are owned by the CORE window manager
// (`window-mgr/view-window-manager.ts`), driven by the `ViewInstance.open`
// flag the dialog flips. Plugins must not manage windows themselves.

import type { HostApi, PluginModule } from '@easydb/shared';
import { openViewsDialog } from '../dialogs/views-dialog.js';

export const meta: NonNullable<PluginModule['meta']> = {
  name: 'views',
  version: '0.1.0',
  description: 'Display tables through HTML view templates in read-only windows.',
  author: 'easyDBAccess built-ins',
  optional: true,
};

// Footer/table buttons render their `icon` as a Material Icons ligature (see
// panel-footer.ts) — NOT as raw SVG (that's the header-button convention). Use
// the icon name here so it renders as a glyph instead of garbled markup.
const VIEWS_ICON = 'grid_view';

// --- Default RSS template ----------------------------------------------------
const RSS_NAME = 'RSS Feed';
const RSS_HEADER = '<div style="display:flex;flex-direction:column;gap:12px;padding:12px;">';
const RSS_ROW = [
  '<div style="border:1px solid #e5e7eb;border-radius:12px;padding:12px 16px;background:#ffffff;box-shadow:0 1px 2px rgba(0,0,0,0.06);">',
  '<a href="$URL" target="_blank" rel="noopener noreferrer" style="font-size:1.05rem;font-weight:600;color:#2563eb;text-decoration:none;">$TITLE</a>',
  '<div style="color:#6b7280;font-size:0.78rem;margin:4px 0;">$DATE</div>',
  '<div style="color:#374151;font-size:0.9rem;line-height:1.45;display:-webkit-box;-webkit-box-orient:vertical;-webkit-line-clamp:20;line-clamp:20;overflow:hidden;">$DESCRIPTION</div>',
  '</div>',
].join('');
const RSS_FOOTER = '</div>';

export function init(api: HostApi): void {
  // Footer "Views" icon on every table. Everything past opening the dialog is
  // core: the dialog flips `ViewInstance.open` and the core view-window manager
  // opens/closes/persists the windows.
  api.ui.registerTableButton({
    id: 'views:open',
    label: 'Views',
    icon: VIEWS_ICON,
    tooltip: 'Views — display this table through a template',
    onClick: (_a, { tableId }) => openViewsDialog(tableId),
  });
}

export async function load(api: HostApi): Promise<void> {
  await seedDefaults(api);
}

/** Signature of the shipped built-in RSS template. Changes whenever the code's
 *  header/row/footer HTML changes, so an already-seeded workspace can be told
 *  its built-in template is out of date and updated in place. */
function rssSignature(): string {
  let h = 5381;
  const s = `${RSS_HEADER}�${RSS_ROW}�${RSS_FOOTER}`;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) | 0;
  return (h >>> 0).toString(36);
}

/**
 * Ensure the built-in RSS template exists and matches the shipped HTML.
 *
 * The template lives in the workspace's IndexedDB, so a new app release does
 * NOT automatically update a workspace that was seeded by an earlier version.
 * We reconcile on every load: seed it once for a fresh workspace, and — when
 * the shipped HTML changes (new signature) — patch the existing built-in copy
 * so fixes (e.g. the description line-clamp) reach workspaces that already have
 * it. A workspace where the user deleted the built-in is left alone (the
 * "seeded" flag records that we've provisioned it once).
 */
async function seedDefaults(api: HostApi): Promise<void> {
  const wsId = api.workspaceId();
  if (!wsId) return;
  const seededKey = `views:seeded:rss:${wsId}`;
  const sigKey = `views:sig:rss:${wsId}`;
  const shipped = rssSignature();

  const existing = (await api.store.viewTemplates.find({ workspaceId: wsId })).find(
    (t) => t.builtin && t.name === RSS_NAME,
  );

  if (existing) {
    const appliedSig = (await api.store.settings.findOne(sigKey))?.value;
    if (appliedSig !== shipped) {
      // Shipped HTML changed since this workspace last saw it — update in place.
      await api.store.viewTemplates.patch(existing.id, {
        headerHtml: RSS_HEADER,
        rowHtml: RSS_ROW,
        footerHtml: RSS_FOOTER,
        updatedAt: Date.now(),
      });
      await api.store.settings.upsert({ key: sigKey, value: shipped });
    }
    await api.store.settings.upsert({ key: seededKey, value: true });
    return;
  }

  // No built-in template present. Only seed if we never have (respect a user
  // who deleted it).
  const seeded = await api.store.settings.findOne(seededKey);
  if (seeded?.value) return;
  await api.store.viewTemplates.insert({
    id: uuid(),
    workspaceId: wsId,
    name: RSS_NAME,
    headerHtml: RSS_HEADER,
    rowHtml: RSS_ROW,
    footerHtml: RSS_FOOTER,
    builtin: true,
    updatedAt: Date.now(),
  });
  await api.store.settings.upsert({ key: seededKey, value: true });
  await api.store.settings.upsert({ key: sigKey, value: shipped });
}

function uuid(): string {
  return (
    globalThis.crypto?.randomUUID?.() ??
    `${Date.now().toString(36)}-${Math.random().toString(36).slice(2)}`
  );
}
